<?php namespace App\Repositories\Library;use App\Repositories\BaseRepository;use App\Models\Library\LibraryMember;use Illuminate\Database\Eloquent\Collection;class LibraryMemberRepository extends BaseRepository{    public function __construct(LibraryMember $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByMemberNo(string $memberNo): ?LibraryMember    {        return $this->query()->where('member_no', $memberNo)->first();    }    public function findByStudent(int $studentId): ?LibraryMember    {        return $this->query()->where('student_id', $studentId)->first();    }    public function findByEmployee(int $employeeId): ?LibraryMember    {        return $this->query()->where('employee_id', $employeeId)->first();    }    public function findByType(string $type): Collection    {        return $this->findByField('member_type', $type);    }    public function getActiveMembers(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getExpiredMemberships(): Collection    {        return $this->query()->where('membership_end', '<', now())->get();    }    public function getExpiringSoon(int $days = 30): Collection    {        return $this->query()->where('membership_end', '>=', now())->where('membership_end', '<=', now()->addDays($days))->get();    }    public function searchMembers(string $keyword): Collection    {        return $this->query()->where('member_no', 'like', "%{$keyword}%")->get();    }    public function getMemberWithIssues(int $memberId): ?LibraryMember    {        return $this->query()->with('bookIssues')->findOrFail($memberId);    }    public function renewMembership(int $id, string $endDate): bool    {        return $this->update($id, ['membership_end' => $endDate, 'is_active' => true]);    }}